3777 // Return true if we can safely remove the select instruction for std::bit_ceil
3778 // pattern.
3779 static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,
3780                                         const APInt *Cond1, Value *CtlzOp,
3781                                         unsigned BitWidth,
3782                                         bool &ShouldDropNoWrap) {
3783   // The challenge in recognizing std::bit_ceil(X) is that the operand is used
3784   // for the CTLZ proper and select condition, each possibly with some
3785   // operation like add and sub.
3786   //
3787   // Our aim is to make sure that -ctlz & (BitWidth - 1) == 0 even when the
3788   // select instruction would select 1, which allows us to get rid of the select
3789   // instruction.
3790   //
3791   // To see if we can do so, we do some symbolic execution with ConstantRange.
3792   // Specifically, we compute the range of values that Cond0 could take when
3793   // Cond == false.  Then we successively transform the range until we obtain
3794   // the range of values that CtlzOp could take.
3795   //
3796   // Conceptually, we follow the def-use chain backward from Cond0 while
3797   // transforming the range for Cond0 until we meet the common ancestor of Cond0
3798   // and CtlzOp.  Then we follow the def-use chain forward until we obtain the
3799   // range for CtlzOp.  That said, we only follow at most one ancestor from
3800   // Cond0.  Likewise, we only follow at most one ancestor from CtrlOp.
3801 
3802   ConstantRange CR = ConstantRange::makeExactICmpRegion(
3803       CmpInst::getInversePredicate(Pred), *Cond1);
3804 
3805   ShouldDropNoWrap = false;
3806 
3807   // Match the operation that's used to compute CtlzOp from CommonAncestor.  If
3808   // CtlzOp == CommonAncestor, return true as no operation is needed.  If a
3809   // match is found, execute the operation on CR, update CR, and return true.
3810   // Otherwise, return false.
3811   auto MatchForward = [&](Value *CommonAncestor) {
3812     const APInt *C = nullptr;
3813     if (CtlzOp == CommonAncestor)
3814       return true;
3815     if (match(CtlzOp, m_Add(m_Specific(CommonAncestor), m_APInt(C)))) {
3816       ShouldDropNoWrap = true;
3817       CR = CR.add(*C);
3818       return true;
3819     }
3820     if (match(CtlzOp, m_Sub(m_APInt(C), m_Specific(CommonAncestor)))) {
3821       ShouldDropNoWrap = true;
3822       CR = ConstantRange(*C).sub(CR);
3823       return true;
3824     }
3825     if (match(CtlzOp, m_Not(m_Specific(CommonAncestor)))) {
3826       CR = CR.binaryNot();
3827       return true;
3828     }
3829     return false;
3830   };
3831 
3832   const APInt *C = nullptr;
3833   Value *CommonAncestor;
3834   if (MatchForward(Cond0)) {
3835     // Cond0 is either CtlzOp or CtlzOp's parent.  CR has been updated.
3836   } else if (match(Cond0, m_Add(m_Value(CommonAncestor), m_APInt(C)))) {
3837     CR = CR.sub(*C);
3838     if (!MatchForward(CommonAncestor))
3839       return false;
3840     // Cond0's parent is either CtlzOp or CtlzOp's parent.  CR has been updated.
3841   } else {
3842     return false;
3843   }
3844 
3845   // Return true if all the values in the range are either 0 or negative (if
3846   // treated as signed).  We do so by evaluating:
3847   //
3848   //   CR - 1 u>= (1 << BitWidth) - 1.
3849   APInt IntMax = APInt::getSignMask(BitWidth) - 1;
3850   CR = CR.sub(APInt(BitWidth, 1));
3851   return CR.icmp(ICmpInst::ICMP_UGE, IntMax);
3852 }
