3854 // Transform the std::bit_ceil(X) pattern like:
3855 //
3856 //   %dec = add i32 %x, -1
3857 //   %ctlz = tail call i32 @llvm.ctlz.i32(i32 %dec, i1 false)
3858 //   %sub = sub i32 32, %ctlz
3859 //   %shl = shl i32 1, %sub
3860 //   %ugt = icmp ugt i32 %x, 1
3861 //   %sel = select i1 %ugt, i32 %shl, i32 1
3862 //
3863 // into:
3864 //
3865 //   %dec = add i32 %x, -1
3866 //   %ctlz = tail call i32 @llvm.ctlz.i32(i32 %dec, i1 false)
3867 //   %neg = sub i32 0, %ctlz
3868 //   %masked = and i32 %ctlz, 31
3869 //   %shl = shl i32 1, %sub
3870 //
3871 // Note that the select is optimized away while the shift count is masked with
3872 // 31.  We handle some variations of the input operand like std::bit_ceil(X +
3873 // 1).
3874 static Instruction *foldBitCeil(SelectInst &SI, IRBuilderBase &Builder,
3875                                 InstCombinerImpl &IC) {
