3877   unsigned BitWidth = SelType->getScalarSizeInBits();
3878   if (!isPowerOf2_32(BitWidth))
3879     return nullptr;
3880 
3881   Value *FalseVal = SI.getFalseValue();
3882   Value *TrueVal = SI.getTrueValue();
3883   CmpPredicate Pred;
3884   const APInt *Cond1;
3885   Value *Cond0, *Ctlz, *CtlzOp;
3886   if (!match(SI.getCondition(), m_ICmp(Pred, m_Value(Cond0), m_APInt(Cond1))))
3887     return nullptr;
3888 
3889   if (match(TrueVal, m_One())) {
3890     std::swap(FalseVal, TrueVal);
3891     Pred = CmpInst::getInversePredicate(Pred);
3892   }
3893 
3894   bool ShouldDropNoWrap;
3895 
3896   if (!match(FalseVal, m_One()) ||
3897       !match(TrueVal,
3898              m_OneUse(m_Shl(m_One(), m_OneUse(m_Sub(m_SpecificInt(BitWidth),
3899                                                     m_Value(Ctlz)))))) ||
3900       !match(Ctlz, m_Intrinsic<Intrinsic::ctlz>(m_Value(CtlzOp), m_Value())) ||
3901       !isSafeToRemoveBitCeilSelect(Pred, Cond0, Cond1, CtlzOp, BitWidth,
3902                                    ShouldDropNoWrap))
3903     return nullptr;
3904 
3905   if (ShouldDropNoWrap) {
3906     cast<Instruction>(CtlzOp)->setHasNoUnsignedWrap(false);
3907     cast<Instruction>(CtlzOp)->setHasNoSignedWrap(false);
3908   }
3909 
3910   // Build 1 << (-CTLZ & (BitWidth-1)).  The negation likely corresponds to a
3911   // single hardware instruction as opposed to BitWidth - CTLZ, where BitWidth
3912   // is an integer constant.  Masking with BitWidth-1 comes free on some
3913   // hardware as part of the shift instruction.
3914 
3915   // Drop range attributes and re-infer them in the next iteration.
3916   cast<Instruction>(Ctlz)->dropPoisonGeneratingAnnotations();
3917   IC.addToWorklist(cast<Instruction>(Ctlz));
